using Microsoft.Extensions.Logging;

namespace MyMauiApp;

public static class MauiProgram
{
    public static MauiApp CreateMauiApp()
    {
        var builder = MauiApp.CreateBuilder();
        builder
            .UseMauiApp<App>()
            .ConfigureFonts(fonts =>
            {
                fonts.AddFont("OpenSans-Regular.ttf", "OpenSansRegular");
            });

        // --- Services ---
        // Singleton: one HttpClient and one DataService instance for the
        // entire app lifetime. This avoids socket exhaustion from repeated
        // HttpClient creation and lets DataService cache or share state
        // (auth tokens, ETags, etc.) across all consumers.
        builder.Services.AddSingleton<HttpClient>(sp =>
        {
            return new HttpClient { BaseAddress = new Uri("https://api.example.com/") };
        });
        builder.Services.AddSingleton<IDataService, DataService>();

        // --- ViewModels ---
        // Transient: a fresh ViewModel every time a page is navigated to.
        // This keeps each page instance working with its own state and
        // avoids stale data when the user navigates back and forth.
        builder.Services.AddTransient<MainViewModel>();
        builder.Services.AddTransient<DetailViewModel>();

        // --- Pages ---
        // Transient: a new page instance per navigation. MAUI's Shell and
        // NavigationPage work best when pages aren't reused, because
        // the navigation stack already manages page lifetimes.
        builder.Services.AddTransient<MainPage>();
        builder.Services.AddTransient<DetailPage>();

#if DEBUG
        builder.Logging.AddDebug();
#endif

        return builder.Build();
    }
}

